import{_ as a,c as l,o as n,ag as e}from"./chunks/framework.B-XtCDNB.js";const D=JSON.parse('{"title":"FlashQL","description":"","frontmatter":{},"headers":[],"relativePath":"flashql.md","filePath":"flashql.md"}'),o={name:"flashql.md"};function t(p,s,r,i,c,F){return n(),l("div",null,[...s[0]||(s[0]=[e(`<h1 id="flashql" tabindex="-1">FlashQL <a class="header-anchor" href="#flashql" aria-label="Permalink to &quot;FlashQL&quot;">​</a></h1><p>FlashQL is LinkedQL&#39;s embeddable SQL runtime.</p><p>It lets you run a real query engine inside:</p><ul><li>the browser</li><li>Node.js</li><li>workers</li><li>edge runtimes</li></ul><p>And it does more than &quot;local SQL in memory.&quot; FlashQL combines:</p><ul><li>a local storage engine</li><li>SQL parsing and execution</li><li>live queries</li><li>WAL/changefeed access</li><li>foreign-client federation</li><li>local-first sync orchestration</li><li>point-in-time boot with version-aware replay</li></ul><p>If LinkedQL is the broad cross-runtime data interface, FlashQL is the place where the full local-first story comes together.</p><h2 id="what-flashql-is-good-at" tabindex="-1">What FlashQL is good at <a class="header-anchor" href="#what-flashql-is-good-at" aria-label="Permalink to &quot;What FlashQL is good at&quot;">​</a></h2><p>FlashQL is especially strong when you need one or more of these:</p><ul><li>a SQL runtime inside an app, worker, or edge process</li><li>a local-first data layer with persistent local state</li><li>the ability to query local and remote relations through one graph</li><li>live queries over local state</li><li>explicit control over caching, materialization, and realtime mirroring</li><li>point-in-time replay and version-bound querying</li></ul><h2 id="a-minimal-flashql-instance" tabindex="-1">A minimal FlashQL instance <a class="header-anchor" href="#a-minimal-flashql-instance" aria-label="Permalink to &quot;A minimal FlashQL instance&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT 2::text AS value</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ value: &#39;2&#39; }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This is the smallest useful FlashQL shape:</p><ul><li>create the client</li><li>connect it</li><li>run SQL</li><li>disconnect it</li></ul><h2 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h2><p>FlashQL is ephemeral by default, but it becomes a serious local runtime when you attach a <code>keyval</code> backend.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> IndexedDBKV</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@webqit/keyval/indexeddb</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  keyval</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> IndexedDBKV</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> path</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">my-app</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>What <code>keyval</code> changes:</p><ul><li>schema and data can survive reloads</li><li>WAL history can be persisted</li><li>sync state can be persisted</li><li>FlashQL becomes appropriate for browser PWAs and local-first apps</li></ul><p>Typical backends include:</p><ul><li>in-memory KV for tests and ephemeral sessions</li><li>IndexedDB-backed KV in the browser</li><li>custom KV adapters for other environments</li></ul><h2 id="dialects" tabindex="-1">Dialects <a class="header-anchor" href="#dialects" aria-label="Permalink to &quot;Dialects&quot;">​</a></h2><p>FlashQL parses and executes both PostgreSQL-flavored and MySQL-flavored SQL.</p><h3 id="set-the-dialect-at-client-level" tabindex="-1">Set the dialect at client level <a class="header-anchor" href="#set-the-dialect-at-client-level" aria-label="Permalink to &quot;Set the dialect at client level&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> dialect</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="override-it-per-query" tabindex="-1">Override it per query <a class="header-anchor" href="#override-it-per-query" aria-label="Permalink to &quot;Override it per query&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT \`name\` FROM \`users\`</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> dialect</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">mysql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>If you do not specify a dialect, FlashQL defaults to <code>postgres</code>.</p><h2 id="the-core-flashql-surface" tabindex="-1">The core FlashQL surface <a class="header-anchor" href="#the-core-flashql-surface" aria-label="Permalink to &quot;The core FlashQL surface&quot;">​</a></h2><p>FlashQL supports the same top-level application contract as the other LinkedQL clients:</p><ul><li><code>db.query()</code></li><li><code>db.stream()</code></li><li><code>db.transaction()</code></li><li><code>db.wal.subscribe()</code></li></ul><p>And then adds local-engine-specific capabilities:</p><ul><li><code>db.storageEngine</code></li><li><code>db.sync</code></li><li><code>versionStop</code></li><li><code>overwriteForward</code></li></ul><h2 id="live-queries-streams-and-wal" tabindex="-1">Live queries, streams, and WAL <a class="header-anchor" href="#live-queries-streams-and-wal" aria-label="Permalink to &quot;Live queries, streams, and WAL&quot;">​</a></h2><p>FlashQL is not just a SQL parser over arrays. It is built to support modern app data flows directly.</p><h3 id="live-queries" tabindex="-1">Live queries <a class="header-anchor" href="#live-queries" aria-label="Permalink to &quot;Live queries&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  &#39;</span><span style="color:#C3E88D;">SELECT id, name FROM public.users ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> result</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">abort</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Use live queries when the UI needs a query-shaped view that updates as local state changes.</p><p>See also: <a href="/capabilities/live-queries">Live Queries</a></p><h3 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> (</span><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> row </span><span style="color:#89DDFF;">of</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM public.big_table ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">row</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><p>Use streams when you want lazy async iteration instead of fully buffered results.</p><p>See also: <a href="/capabilities/streaming">Streaming</a></p><h3 id="wal-subscriptions" tabindex="-1">WAL subscriptions <a class="header-anchor" href="#wal-subscriptions" aria-label="Permalink to &quot;WAL subscriptions&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> unsubscribe </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">wal</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">subscribe</span><span style="color:#BABED8;">(</span></span>
<span class="line"><span style="color:#89DDFF;">  {</span><span style="color:#F07178;"> public</span><span style="color:#89DDFF;">:</span><span style="color:#BABED8;"> [</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">] </span><span style="color:#89DDFF;">},</span></span>
<span class="line"><span style="color:#89DDFF;">  (</span><span style="color:#BABED8;font-style:italic;">commit</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#BABED8;"> console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(commit)</span></span>
<span class="line"><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#82AAFF;"> unsubscribe</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Use WAL subscriptions when you care about table-level commits directly.</p><p>See also: <a href="/capabilities/changefeeds">Changefeeds</a></p><h2 id="transactions-and-mvcc" tabindex="-1">Transactions and MVCC <a class="header-anchor" href="#transactions-and-mvcc" aria-label="Permalink to &quot;Transactions and MVCC&quot;">​</a></h2><p>FlashQL is transaction-first. It exposes both a SQL-facing query surface and a lower-level storage transaction surface.</p><h3 id="query-level-transaction" tabindex="-1">Query-level transaction <a class="header-anchor" href="#query-level-transaction" aria-label="Permalink to &quot;Query-level transaction&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">transaction</span><span style="color:#BABED8;">(</span><span style="color:#C792EA;">async</span><span style="color:#89DDFF;"> (</span><span style="color:#BABED8;font-style:italic;">tx</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#C792EA;">  const</span><span style="color:#BABED8;"> table</span><span style="color:#89DDFF;"> =</span><span style="color:#BABED8;"> tx</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">getTable</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> namespace</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">  await</span><span style="color:#BABED8;"> table</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">insert</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> id</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 1</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> name</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">Ada</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>Internally, FlashQL&#39;s storage engine uses MVCC-oriented versioning and WAL replay to support:</p><ul><li>isolated transactional work</li><li>live-query invalidation and diffing</li><li>version-aware replay to earlier points in history</li></ul><h2 id="foreign-data-and-local-first-orchestration" tabindex="-1">Foreign data and local-first orchestration <a class="header-anchor" href="#foreign-data-and-local-first-orchestration" aria-label="Permalink to &quot;Foreign data and local-first orchestration&quot;">​</a></h2><p>This is where FlashQL goes beyond a plain embedded database.</p><p>FlashQL can attach foreign clients, register foreign namespaces, and expose upstream data locally through views that behave in one of three ways:</p><ul><li><code>origin</code>: federated at read time</li><li><code>materialized</code>: copied locally on sync</li><li><code>realtime</code>: copied locally and kept hot after sync</li></ul><p>That model is documented in detail here:</p><ul><li><a href="/flashql/foreign-io">Federation, Materialization, and Realtime Views</a></li><li><a href="/flashql/sync">FlashQL Sync</a></li></ul><h2 id="point-in-time-boot" tabindex="-1">Point-in-time boot <a class="header-anchor" href="#point-in-time-boot" aria-label="Permalink to &quot;Point-in-time boot&quot;">​</a></h2><p>FlashQL can open its local store at an earlier relation version.</p><h3 id="read-only-historical-boot" tabindex="-1">Read-only historical boot <a class="header-anchor" href="#read-only-historical-boot" aria-label="Permalink to &quot;Read-only historical boot&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> historical </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  versionStop</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public.snap_tbl@1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> historical</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>With <code>versionStop</code>, FlashQL replays persisted history until the last matching relation version and boots there.</p><p>By default, that boot is read-only.</p><h3 id="overwrite-forward-boot" tabindex="-1">Overwrite-forward boot <a class="header-anchor" href="#overwrite-forward-boot" aria-label="Permalink to &quot;Overwrite-forward boot&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> branch </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  keyval</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  versionStop</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">public.snap_tbl@1</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  overwriteForward</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> branch</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>With <code>overwriteForward: true</code>, FlashQL keeps the full history until the first mutating commit, then truncates forward history and lets you continue from that historical point.</p><p>This is documented in more detail in:</p><ul><li><a href="/capabilities/version-binding">Version Binding</a></li><li><a href="/flashql/lang">FlashQL Language Reference</a></li></ul><h2 id="what-flashql-does-not-try-to-be" tabindex="-1">What FlashQL does not try to be <a class="header-anchor" href="#what-flashql-does-not-try-to-be" aria-label="Permalink to &quot;What FlashQL does not try to be&quot;">​</a></h2><p>FlashQL is ambitious, but it is still useful to say what it is not trying to do.</p><ul><li>It is not a byte-for-byte clone of PostgreSQL or MySQL.</li><li>It does not claim universal support for every DDL and operational feature from mainstream servers.</li><li>Some schema-evolution surfaces are still catching up.</li></ul><p>The goal is application-level SQL power, not a full replacement for every server-side database responsibility.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="/flashql/lang">Language Reference</a></li><li><a href="/flashql/foreign-io">Federation, Materialization, and Realtime Views</a></li><li><a href="/flashql/sync">FlashQL Sync</a></li><li><a href="/docs/query-api">Query Interface</a></li></ul>`,76)])])}const d=a(o,[["render",t]]);export{D as __pageData,d as default};
